import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Встановлення Fabric","description":"Покрокова інструкція зі встановлення Fabric.","frontmatter":{"title":"Встановлення Fabric","description":"Покрокова інструкція зі встановлення Fabric.","authors":["Benonardo","IMB11","modmuss50"],"files":[]},"headers":[],"relativePath":"uk_ua/1.21.4/players/installing-fabric.md","filePath":"versions/1.21.4/translated/uk_ua/players/installing-fabric.md","lastUpdated":1760721669000}`);var c={name:`uk_ua/1.21.4/players/installing-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Встановлення Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Встановлення Fabric”">​</a></h1><p>Цей посібник стосується лише офіційного запускача Minecraft. Для запускачів сторонніх розробників слід ознайомитися з їх документацією.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Завантажте встановлювач Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Завантажте встановлювач Fabric”">​</a></h2><p>Ви можете завантажити встановлювач Fabric із <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">сайту Fabric</a>.</p><p>Якщо ви користуєтеся Windows, завантажте версію <code>.exe</code> (<code>Download For Windows</code>), оскільки для цього не потрібно встановлювати Java у вашій системі. Натомість він використовує Java, яка постачається з офіційним запускачем.</p><p>Для macOS та Linux вам слід завантажити <code>jar</code> версію. Іноді перед цим кроком потрібно встановити Java.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Запустіть встановлювач Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Запустіть встановлювач Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Перш ніж запустити встановлювач, закрийте Minecraft і запускач Minecraft.</p></div><details class="details custom-block"><summary>Інформація для користувачів MacOS</summary><p>У macOS вам може знадобитися натиснути ПКМ по файлу <code>.jar</code> у каталозі завантажень і натиснути <code>Відкрити</code>, щоб запустити його.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Контекстне меню MacOS у Fabric Installer" loading="lazy"></p><p>Коли вас запитають «Ви впевнені, що хочете відкрити?», знову натисніть <code>Відкрити</code>.</p></details><p>Відкривши встановлювач, ви повинні побачити такий екран:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Встановлювач Fabric із виділеним «встановити»" loading="lazy"></p><p>Щоб установити Fabric, просто виберіть свою версію гри зі спадного меню та натисніть «встановити».</p><div class="warning custom-block"><p class="custom-block-title">ВАЖЛИВО</p><p>Переконайтеся, що позначено «Створити профіль».</p></div><h2 id="3-you-re-done" tabindex="-1">3. Готово! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. Готово!”">​</a></h2><p>Після завершення встановлення ви можете відкрити запускач Minecraft і вибрати профіль Fabric зі спадного списку в нижньому лівому куті та натиснути грати!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Запускач Minecraft з вибраним профілем Fabric" loading="lazy"></p><p>Тепер, коли ви встановили Fabric, ви можете додавати моди у свою гру! Перегляньте посібник <a href="./finding-mods">пошуку надійних модів</a>, щоб дізнатися більше.</p><p>Якщо під час виконання цього посібника у вас виникнуть проблеми, ви можете звернутися за допомогою до <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> на каналі <code>#player-support</code>.</p>`,18)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};